// ==============================================================
// WEB SEARCH + IMAGE GENERATION INPUT
// Edit TOPIC and DESCRIPTION to search and generate images
// ==============================================================

const TOPIC = 'The future of remote work and hybrid teams';

const DESCRIPTION = `Explore how companies are adapting to permanent hybrid work models, 
including new tools for async collaboration, virtual office spaces, and 
work-life balance strategies for distributed teams in 2026.`;

return [{ json: { topic: TOPIC, description: DESCRIPTION } }];

// Combine topic, description, and web search results into a detailed image prompt

const inputs = $('set_search_topic').first().json;
const topic = inputs.topic;
const description = inputs.description;

// Collect web search results
let researchContext = '';
try {
  const results = $input.all()
    .filter(r => r.json && r.json.title)
    .slice(0, 6)
    .map((r, idx) => `${idx + 1}. ${r.json.title}: ${(r.json.description || '').substring(0, 120)}`);

  if (results.length > 0) {
    researchContext = results.join('\n');
  }
} catch(e) {
  console.log('Web search error:', e.message);
}

// Build a comprehensive image generation prompt
const imagePrompt = `Create a professional, editorial-quality infographic illustration for LinkedIn about: ${topic}

Context: ${description}

Visual Requirements:
- Professional B2B style suitable for LinkedIn
- Modern, clean design with a cohesive color palette
- 1440x756px landscape format
- Include 3-5 key visual elements representing main concepts
- Use clear labels and readable text (max 5 words per label)
- Incorporate modern design trends: gradient backgrounds, 3D elements, or isometric style
- NOT a flat 2D flowchart - make it visually engaging

Research Context (use for accuracy and current trends):
${researchContext || '(No web research available - use general knowledge)'}

Style: Ultra-detailed editorial illustration, crisp rendering, professional quality, modern color scheme (suggest blues, purples, or greens), appropriate for business social media.`;

return [{ json: { prompt: imagePrompt, topic, description } }];

// Decode Gemini image output and save with topic-based filename
const ts = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
const topicLabel = ($('set_search_topic').first().json.topic || 'search_image')
  .toLowerCase().replace(/[^a-z0-9]+/g, '_').substring(0, 40);
const filename = topicLabel + '_' + ts;

const nativeBinary = $input.first().binary?.data;
let imageBuffer, mimeType;

if (nativeBinary) {
  mimeType = nativeBinary.mimeType || 'image/jpeg';
  imageBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');
} else {
  const response = $input.first().json;
  const parts = response.candidates?.[0]?.content?.parts || [];
  const imgPart = parts.find(p => p.inlineData && (p.inlineData.mimeType || '').startsWith('image/'));

  if (!imgPart) {
    const txt = parts.filter(p => p.text).map(p => p.text).join('\n');
    throw new Error('No image in response. Model output: ' + txt.substring(0, 500));
  }

  mimeType = imgPart.inlineData.mimeType || 'image/jpeg';
  imageBuffer = Buffer.from(imgPart.inlineData.data, 'base64');
}

const ext = mimeType.includes('jpeg') ? 'jpg' : 'png';
const finalFilename = filename + '.' + ext;
const imageBinary = await this.helpers.prepareBinaryData(imageBuffer, finalFilename, mimeType);

return [{ 
  json: { 
    filename: finalFilename, 
    mimeType, 
    size_bytes: imageBuffer.length,
    generated_at: new Date().toISOString()
  }, 
  binary: { image: imageBinary } 
}];
